module d_ff_async_clear (
    input wire clk,
    input wire clear,
    input wire d,
    output reg q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge clear or posedge dbg_halt) begin
        if (clear)
            q <= 1'b0;
        else
            q <= d;
    end

endmodule
